fn registry() -> Map<String, Value> {
    serde_json::from_str(SCHEMA_REGISTRY_JSON).expect("generated schema registry")
}

fn resolve_pointer<'a>(document: &'a Value, pointer: &str) -> Result<&'a Value, String> {
    if pointer.is_empty() || pointer == "#" {
        return Ok(document);
    }
    let json_pointer = pointer
        .strip_prefix('#')
        .ok_or_else(|| format!("unsupported ref pointer: {pointer}"))?;
    document
        .pointer(json_pointer)
        .ok_or_else(|| format!("invalid ref pointer: {pointer}"))
}

fn resolve_reference<'a>(
    registry: &'a Map<String, Value>,
    reference: &str,
    current_id: &str,
) -> Result<(&'a Value, String), String> {
    let (document_name, fragment) = reference.split_once('#').unwrap_or((reference, ""));
    let schema_id = if document_name.is_empty() {
        current_id.to_owned()
    } else {
        registry
            .keys()
            .find(|candidate| *candidate == document_name || candidate.ends_with(&format!("/{document_name}")))
            .cloned()
            .ok_or_else(|| format!("unknown schema reference: {reference}"))?
    };
    let document = registry.get(&schema_id).ok_or_else(|| "missing schema".to_owned())?;
    let pointer = if fragment.is_empty() { "#".to_owned() } else { format!("#{fragment}") };
    Ok((resolve_pointer(document, &pointer)?, schema_id))
}

fn validate(
    registry: &Map<String, Value>,
    schema: &Value,
    value: &Value,
    schema_id: &str,
    location: &str,
) -> Vec<String> {
    if schema == &Value::Bool(false) {
        return vec![format!("{location}: value is forbidden")];
    }
    if schema == &Value::Bool(true) {
        return Vec::new();
    }
    if let Some(reference) = schema.get("$ref").and_then(Value::as_str) {
        return match resolve_reference(registry, reference, schema_id) {
            Ok((resolved, resolved_id)) => validate(registry, resolved, value, &resolved_id, location),
            Err(error) => vec![error],
        };
    }
    let mut errors = Vec::new();
    if let Some(one_of) = schema.get("oneOf").and_then(Value::as_array) {
        let matches = one_of
            .iter()
            .filter(|candidate| validate(registry, candidate, value, schema_id, location).is_empty())
            .count();
        if matches != 1 {
            errors.push(format!("{location}: expected exactly one union variant"));
        }
    }

    if let Some(constant) = schema.get("const") {
        if constant != value {
            errors.push(format!("{location}: expected constant"));
        }
    }
    if let Some(values) = schema.get("enum").and_then(Value::as_array) {
        if !values.contains(value) {
            errors.push(format!("{location}: value is not in the closed enum"));
        }
    }

    match schema.get("type").and_then(Value::as_str) {
        Some("object") => {
            let Some(object) = value.as_object() else {
                errors.push(format!("{location}: expected object"));
                return errors;
            };
            let properties = schema.get("properties").and_then(Value::as_object);
            if let Some(required) = schema.get("required").and_then(Value::as_array) {
                for field in required.iter().filter_map(Value::as_str) {
                    if !object.contains_key(field) {
                        errors.push(format!("{location}: missing required field {field}"));
                    }
                }
            }
            if schema.get("additionalProperties") == Some(&Value::Bool(false)) {
                for field in object.keys() {
                    if !properties.is_some_and(|items| items.contains_key(field)) {
                        errors.push(format!("{location}: unknown field {field}"));
                    }
                }
            }
            if let Some(properties) = properties {
                for (field, child) in properties {
                    if let Some(child_value) = object.get(field) {
                        errors.extend(validate(
                            registry,
                            child,
                            child_value,
                            schema_id,
                            &format!("{location}.{field}"),
                        ));
                    }
                }
            }
        }
        Some("array") => {
            let Some(items) = value.as_array() else {
                errors.push(format!("{location}: expected array"));
                return errors;
            };
            if schema
                .get("maxItems")
                .and_then(Value::as_u64)
                .is_some_and(|maximum| items.len() as u64 > maximum)
            {
                errors.push(format!("{location}: too many items"));
            }
            if let Some(item_schema) = schema.get("items") {
                for (index, item) in items.iter().enumerate() {
                    errors.extend(validate(
                        registry,
                        item_schema,
                        item,
                        schema_id,
                        &format!("{location}[{index}]"),
                    ));
                }
            }
        }
        Some("string") => {
            let Some(text) = value.as_str() else {
                errors.push(format!("{location}: expected string"));
                return errors;
            };
            if schema
                .get("minLength")
                .and_then(Value::as_u64)
                .is_some_and(|minimum| text.chars().count() < minimum as usize)
            {
                errors.push(format!("{location}: string is too short"));
            }
            if schema
                .get("maxLength")
                .and_then(Value::as_u64)
                .is_some_and(|maximum| text.chars().count() > maximum as usize)
            {
                errors.push(format!("{location}: string is too long"));
            }
            if let Some(pattern) = schema.get("pattern").and_then(Value::as_str) {
                match Regex::new(pattern) {
                    Ok(expression) if !expression.is_match(text) => {
                        errors.push(format!("{location}: string does not match pattern"));
                    }
                    Err(error) => errors.push(format!("{location}: invalid schema pattern: {error}")),
                    _ => {}
                }
            }
            if schema.get("format").and_then(Value::as_str) == Some("date-time")
                && DateTime::parse_from_rfc3339(text).is_err()
            {
                errors.push(format!("{location}: invalid date-time"));
            }
        }
        Some("integer") => {
            if !value.is_i64() && !value.is_u64() {
                errors.push(format!("{location}: expected integer"));
                return errors;
            }
        }
        Some("number") => {
            if !value.is_number() {
                errors.push(format!("{location}: expected number"));
                return errors;
            }
        }
        Some("boolean") => {
            if !value.is_boolean() {
                errors.push(format!("{location}: expected boolean"));
                return errors;
            }
        }
        _ => {}
    }

    if let Some(number) = value.as_f64() {
        if schema
            .get("minimum")
            .and_then(Value::as_f64)
            .is_some_and(|minimum| number < minimum)
        {
            errors.push(format!("{location}: number is below minimum"));
        }
        if schema
            .get("maximum")
            .and_then(Value::as_f64)
            .is_some_and(|maximum| number > maximum)
        {
            errors.push(format!("{location}: number is above maximum"));
        }
    }
    errors
}

pub fn decode_contract(reference: &str, value: &Value) -> Result<(), Vec<String>> {
    let registry = registry();
    let first_id = registry.keys().min().expect("schema registry");
    let (schema, schema_id) =
        resolve_reference(&registry, reference, first_id).map_err(|error| vec![error])?;
    let errors = validate(&registry, schema, value, &schema_id, "$");
    if errors.is_empty() { Ok(()) } else { Err(errors) }
}

macro_rules! define_contract_type {
    ($name:ident, $reference:literal) => {
        #[derive(Clone, Debug, PartialEq)]
        pub struct $name(pub Value);

        impl TryFrom<Value> for $name {
            type Error = Vec<String>;

            fn try_from(value: Value) -> Result<Self, Self::Error> {
                decode_contract($reference, &value)?;
                Ok(Self(value))
            }
        }
    };
}

